mapper.sql:
SELECT ROW_NUMBER() OVER(ORDER BY SORT_LVL, SORT_ODR, A.EXAM_CTGR_LV, A.EXAM_CTGR_SEQ) AS LINE_NO , A.* , COUNT(A.QBNK_QSTN_ID) OVER() AS TOTAL_CNT FROM ( SELECT A.QBNK_QSTN_ID , A.EXAM_QBNK_CTGRCD , A.UP_EXAM_QBNK_CTGRCD , A.QSTN_SEQNO , A.CNDDT_ID , A.TTL , A.QSTN_CTS , A.EXMPL01, A.EXMPL02, A.EXMPL03, A.EXMPL04, A.EXMPL05 , A.EXMPL06, A.EXMPL07, A.EXMPL08, A.EXMPL09, A.EXMPL10 , A.MLT_CRANSYN , A.MLT_CRANS_TYCD , A.MLT_CRANS , A.RGT_ANSR1, A.RGT_ANSR2, A.RGT_ANSR3, A.CRANS4, A.CRANS5 , A.QSTN_EXPLN , A.QSTN_TYCD , A.QSTN_SCR , A.QSTN_DFCTLV , CASE A.QSTN_DFCTLV WHEN 'RAW' THEN '하' WHEN 'MID' THEN '중' WHEN 'HIGH' THEN '상' ELSE '상관없음' END AS QSTN_DIFF_NM , A.WHOL_CRANS_PROCYN , A.EDTRYN , A.DELYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , NVL(A.CRS_ID, A.CRS_NO2) AS CRS_ID
, CASE WHEN A.UP_EXAM_QBNK_CTGRCD IS NULL THEN '-' ELSE A.EXAM_CTGRNM END AS EXAM_CTGRNM , CASE WHEN A.UP_EXAM_QBNK_CTGRCD IS NULL THEN A.EXAM_CTGRNM ELSE (SELECT EXAM_CTGRNM FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD) END AS PAR_EXAM_CTGR_NM , (SELECT EXAM_CTGR_SEQ FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD) AS PAR_EXAM_CTGR_ODR , (SELECT CRSNM FROM TB_LMS_CRS WHERE CRS_ID = NVL(A.CRS_ID, A.CRS_NO2)) AS CRSNM , A.USER_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS USERNM
, (SELECT CDNM FROM TB_ORG_CODE WHERE CTGRCD = 'QSTN_TYCD' AND CD = A.QSTN_TYCD AND ROWNUM = 1) AS QSTN_TYPE_NM , (CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL01)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL02)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL03)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL04)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL05)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL06)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL07)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL08)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL09)),0) = 0) THEN 0 ELSE 1 END +CASE WHEN (NVL(LENGTH(TRIM(A.EXMPL10)),0) = 0)THEN 0 ELSE 1 END ) AS EMPL_CNT , CASE WHEN UP_EXAM_QBNK_CTGRCD IS NULL THEN EXAM_CTGR_LV ELSE (SELECT EXAM_CTGR_LV FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD) END AS SORT_LVL , CASE WHEN UP_EXAM_QBNK_CTGRCD IS NULL THEN EXAM_CTGR_SEQ ELSE (SELECT EXAM_CTGR_SEQ FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD) END AS SORT_ODR , A.EXAM_CTGR_LV , A.EXAM_CTGR_SEQ FROM ( SELECT AA.* , BB.UP_EXAM_QBNK_CTGRCD , BB.EXAM_CTGRNM , BB.EXAM_CTGR_LV , BB.EXAM_CTGR_SEQ , BB.USER_ID , BB.CRS_ID as CRS_NO2 FROM TB_LMS_QBNK_QSTN AA JOIN TB_LMS_EXAM_QBANK_CTGR BB ON AA.EXAM_QBNK_CTGRCD = BB.EXAM_QBNK_CTGRCD AND AA.DELYN = 'N' AND BB.DELYN = 'N' UNION ALL SELECT AA.* , NULL AS UP_EXAM_QBNK_CTGRCD , '-' AS EXAM_CTGRNM , 1 AS EXAM_CTGR_LV , AA.CNDDT_ID AS EXAM_CTGR_SEQ , AA.RGTR_ID AS USER_ID , NULL AS CRS_NO2 FROM TB_LMS_QBNK_QSTN AA WHERE AA.EXAM_QBNK_CTGRCD = '-' AND AA.DELYN = 'N' ) A WHERE 1 = 1
AND ( A.CRS_ID = #{crsNo} OR A.CRS_NO2 = #{crsNo} )
AND A.QBNK_QSTN_ID = #{examQbankQstnSn}
AND A.USER_ID = #{userId}
AND A.EXAM_QBNK_CTGRCD = #{examQbankCtgrCd}
AND ( A.UP_EXAM_QBNK_CTGRCD = #{parExamQbankCtgrCd} OR A.EXAM_QBNK_CTGRCD = #{parExamQbankCtgrCd} )
AND ( LOWER(A.EXAM_CTGRNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT EXAM_CTGRNM FROM TB_LMS_EXAM_QBANK_CTGR WHERE EXAM_QBNK_CTGRCD = A.UP_EXAM_QBNK_CTGRCD)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER((SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID)) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.TTL) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.QSTN_SEQNO = #{qstnNo}
) A WHERE 1 = 1
AND A.CRS_ID IN ( SELECT DISTINCT BB.CRS_ID FROM TB_LMS_SBJCT AA JOIN TB_LMS_CRS BB ON AA.CRS_ID = BB.CRS_ID AND AA.DELYN = 'N' AND BB.DELYN = 'N' WHERE AA.SBJCT_ID IN (SELECT SBJCT_ID FROM SBJCT_PROF WHERE USER_ID = #{searchKey} AND PROF_TYCD = 'PROFESSOR' AND RPRSYN = 'Y')
AND AA.SBJCT_ID = #{creYear}
AND AA.CRS_ID = #{creTerm}
)

mapper.insert:
		/*
             SQL ID : ExamQbankQstnDAO.insertQbankQstn
            	 설  명 : 문제은행 문제 등록
         */
    	INSERT INTO TB_LMS_QBNK_QSTN (
    		  QBNK_QSTN_ID
			, EXAM_QBNK_CTGRCD
			, QSTN_SEQNO
			, CNDDT_ID
			, CRS_ID
			, TTL
			, QSTN_CTS
			, EXMPL01
			, EXMPL02
			, EXMPL03
			, EXMPL04
			, EXMPL05
			, EXMPL06
			, EXMPL07
			, EXMPL08
			, EXMPL09
			, EXMPL10
			, MLT_CRANSYN
			, MLT_CRANS_TYCD
			, MLT_CRANS
			, RGT_ANSR1
			, RGT_ANSR2
			, RGT_ANSR3
			, CRANS4
			, CRANS5
			, QSTN_EXPLN
			, QSTN_TYCD
			, QSTN_SCR
			, QSTN_DFCTLV
			, WHOL_CRANS_PROCYN
			, EDTRYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) VALUES (
    		  #{examQbankQstnSn}
    		, #{examQbankCtgrCd}
    		, #{qstnNo}
    		, #{subNo}
    		, #{crsNo}
    		, #{TTL}
    		, #{qstnCts}
    		, #{empl1}
    		, #{empl2}
    		, #{empl3}
    		, #{empl4}
    		, #{empl5}
    		, #{empl6}
    		, #{empl7}
    		, #{empl8}
    		, #{empl9}
    		, #{empl10}
    		, #{multiRgtChoiceYn}
    		, #{multiRgtChoiceTypeCd}
    		, #{multiRgtAnsr}
    		, #{rgtAnsr1}
    		, #{rgtAnsr2}
    		, #{rgtAnsr3}
    		, #{rgtAnsr4}
    		, #{rgtAnsr5}
    		, #{qstnExpl}
    		, #{qstnTypeCd}
    		, #{qstnScore}
    		, #{qstnDiff}
    		, #{errorAnsrYn}
    		, #{editorYn}
    		, #{rgtrId}
    		, FN_DTTM()
    		, #{mdfrId}
    		, FN_DTTM()
    	)

mapper.update:
		/*
             SQL ID : ExamQbankQstnDAO.updateQbankQstn
            	 설  명 : 문제은행 문제 수정
         */
    	UPDATE TB_LMS_QBNK_QSTN SET
    		  MDFR_ID = #{mdfrId}
			, MOD_DTTM = FN_DTTM()

			, EXAM_QBNK_CTGRCD = #{examQbankCtgrCd}


			, QSTN_SEQNO = #{qstnNo}


			, CNDDT_ID = #{subNo}


			, CRS_ID = #{crsNo}


			, TTL = #{TTL}


			, QSTN_CTS = #{qstnCts}

			, EXMPL01 = #{empl1}
			, EXMPL02 = #{empl2}
			, EXMPL03 = #{empl3}
			, EXMPL04 = #{empl4}
			, EXMPL05 = #{empl5}
			, EXMPL06 = #{empl6}
			, EXMPL07 = #{empl7}
			, EXMPL08 = #{empl8}
			, EXMPL09 = #{empl9}
			, EXMPL10 = #{empl10}
			, MLT_CRANSYN = #{multiRgtChoiceYn}
			, MLT_CRANS_TYCD = #{multiRgtChoiceTypeCd}
			, MLT_CRANS = #{multiRgtAnsr}

			, RGT_ANSR1 = #{rgtAnsr1}


			, RGT_ANSR2 = #{rgtAnsr2}


			, RGT_ANSR3 = #{rgtAnsr3}


			, CRANS4 = #{rgtAnsr4}


			, CRANS5 = #{rgtAnsr5}


			, QSTN_EXPLN = #{qstnExpl}


			, QSTN_TYCD = #{qstnTypeCd}


			, QSTN_SCR = #{qstnScore}


			, QSTN_DFCTLV = #{qstnDiff}

			, WHOL_CRANS_PROCYN = #{errorAnsrYn}

			, EDTRYN = #{editorYn}


			, DELYN = #{delYn}

    	 WHERE QBNK_QSTN_ID = #{examQbankQstnSn}

	/*
	 	SQL ID : ExamQbankQstnDAO.updateQstnNo
	 	설  명 : 문제은행 문제 순서 변경
 	*/
	UPDATE TB_LMS_QBNK_QSTN SET
		QSTN_SEQNO = QSTN_SEQNO - 1
	 WHERE EXAM_QBNK_CTGRCD = #{examQbankCtgrCd}
	   AND QSTN_SEQNO > #{qstnNo}

	/*
	 	SQL ID : ExamQbankQstnDAO.updateQbankQstnDelYn
	 	설  명 : 문제은행 문제 삭제 상태로 수정
 	*/
	UPDATE TB_LMS_QBNK_QSTN SET
		  MDFR_ID = #{mdfrId}
		, MOD_DTTM = FN_DTTM()
		, DELYN = 'Y'
	 WHERE QBNK_QSTN_ID = #{examQbankQstnSn}
